@page "/Account/Login"
@using Microsoft.AspNetCore.Identity
@using sv_2786e741c4be4bb0b21496e562281407.Data
@inject SignInManager<ApplicationUser> SignInManager
@inject NavigationManager Navigation

<PageTitle>Login</PageTitle>

<div class="row justify-content-center mt-5">
    <div class="col-md-4">
        <h3>Login</h3>

        @if (!string.IsNullOrEmpty(errorMessage))
        {
            <div class="alert alert-danger">@errorMessage</div>
        }

        <form method="post" @formname="login">
            <AntiforgeryToken />
            <div class="mb-3">
                <label class="form-label">Email</label>
                <input type="email" name="Input.Email" class="form-control" @bind="Input.Email" required />
            </div>
            <div class="mb-3">
                <label class="form-label">Password</label>
                <input type="password" name="Input.Password" class="form-control" @bind="Input.Password" required />
            </div>
            <button type="submit" class="btn btn-primary w-100">Log in</button>
        </form>
    </div>
</div>

@code {
    private string? errorMessage;

    [SupplyParameterFromForm]
    private LoginInput Input { get; set; } = new();

    [SupplyParameterFromQuery]
    private string? ReturnUrl { get; set; }

    protected override async Task OnInitializedAsync()
    {
        if (HttpMethods.IsPost(HttpContextAccessor.HttpContext!.Request.Method))
        {
            await HandleLogin();
        }
    }

    [CascadingParameter]
    public HttpContext HttpContextAccessor { get; set; } = default!;

    private async Task HandleLogin()
    {
        var result = await SignInManager.PasswordSignInAsync(
            Input.Email, Input.Password, isPersistent: false, lockoutOnFailure: false);

        if (result.Succeeded)
        {
            Navigation.NavigateTo(ReturnUrl ?? "/", forceLoad: true);
        }
        else
        {
            errorMessage = "Invalid email or password.";
        }
    }

    private sealed class LoginInput
    {
        public string Email { get; set; } = "";
        public string Password { get; set; } = "";
    }
}

@page "/Account/Logout"
